import { useEffect, useState } from "react";

// ── Quizzes (driver knowledge tests) ─────────────────────────────────────────
// Each numbered test has its OWN dedicated 40-question bank (distinct from every
// other test). "Marathon" quizzes are the union of their series. Banks live in
// the B_* consts below and are seeded as defaults; customs are stored in
// localStorage. (Banks were authored per-topic so tests do not overlap.)

export type QuizQuestion = {
    id: string;
    prompt: string;
    options: string[];
    answer: number;        // index into options of the correct choice
    image?: string;        // optional image (URL or data URI) shown with the question
    explanation?: string;  // optional rationale revealed after answering / in review
};

