export function totalQuestions(quiz: Quiz): number {
    return quiz.questions.length;
}
export function quizPassMark(quiz: Quiz): number {
    return Math.ceil((quiz.passPct / 100) * quiz.questions.length);
}

export const TEST_LENGTHS = [10, 20, 25, 30, 40] as const;
export function testQuestions(quiz: Quiz, count?: number): QuizQuestion[] {
    return count && count > 0 && count < quiz.questions.length ? quiz.questions.slice(0, count) : quiz.questions;
}
export function testLength(quiz: Quiz, count?: number): number {
    return count && count > 0 ? Math.min(count, quiz.questions.length) : quiz.questions.length;
}
export function testPassMark(quiz: Quiz, count?: number): number {
    return Math.ceil((quiz.passPct / 100) * testLength(quiz, count));
}

const KEY = "hp_quizzes_v4";
const EVENT = "hp-quizzes-change";

function load(): Quiz[] {
    try {
        const raw = localStorage.getItem(KEY);
        if (raw) {
            const saved = JSON.parse(raw) as Quiz[];
            const customs = saved.filter((c) => !SEED_QUIZZES.some((d) => d.id === c.id));
            return [...SEED_QUIZZES, ...customs];
        }
    } catch { /* ignore */ }
    return SEED_QUIZZES;
}
function persist(list: Quiz[]) {
    const customs = list.filter((c) => !c.locked && !SEED_QUIZZES.some((d) => d.id === c.id));
    localStorage.setItem(KEY, JSON.stringify(customs));
    window.dispatchEvent(new CustomEvent(EVENT));
}

export function useQuizzes() {
    const [quizzes, setQuizzes] = useState<Quiz[]>(load);
    useEffect(() => {
        const h = () => setQuizzes(load());
        window.addEventListener(EVENT, h);
        return () => window.removeEventListener(EVENT, h);
    }, []);
    const save = (qz: Quiz) => {
        const cur = load();
        const idx = cur.findIndex((x) => x.id === qz.id);
        persist(idx >= 0 ? cur.map((x) => (x.id === qz.id ? qz : x)) : [...cur, qz]);
    };
    const remove = (id: string) => persist(load().filter((x) => x.id !== id));
    return { quizzes, save, remove };
}

export function getQuiz(id: string): Quiz | undefined {
    return load().find((qz) => qz.id === id);
}
export function quizTitle(id: string): string {
    return getQuiz(id)?.title ?? id;
}
